    drawTextEx(self, text, x, y, size_px, color, &0);
}

pub fn drawTextEx(self: *TextEngine, text: []const u8, x: f32, y: f32, size_px: u16, color: Color, letter_spacing: f32) void {
    const lm = lineMetrics(self, size_px);
    var pen_x = x;
    const baseline_y = y + lm.ascent;
    var i: usize = 0;
    while (i < text.len) {
        const ch = decodeUtf8(text[i..]);
        if (rasterizeGlyph(self, ch.codepoint, size_px)) |g| {
            if (g.texture) |tex| {
                if (g.is_color) {
                    _ = c.SDL_SetTextureColorMod(tex, 255, 255, 255);
                    _ = c.SDL_SetTextureAlphaMod(tex, 255);
                } else {
                    _ = c.SDL_SetTextureColorMod(tex, color.r, color.g, color.b);
                    _ = c.SDL_SetTextureAlphaMod(tex, color.a);
                }
                const dw: i32 = if (g.scale < 1.0) @intFromFloat(@as(f32, @floatFromInt(g.width)) * g.scale) else g.width;
                const dh: i32 = if (g.scale < 1.0) @intFromFloat(@as(f32, @floatFromInt(g.height)) * g.scale) else g.height;
                const dbx: f32 = @as(f32, @floatFromInt(g.bearing_x)) * g.scale;
                const dby: f32 = @as(f32, @floatFromInt(g.bearing_y)) * g.scale;
                var dst = c.SDL_Rect{ .x = @intFromFloat(pen_x + dbx), .y = @intFromFloat(baseline_y - dby), .w = dw, .h = dh };
                _ = c.SDL_RenderCopy(self.renderer, tex, null, &dst);
            }
            pen_x += @floatFromInt(g.advance);
            pen_x += letter_spacing;
        }
        i += ch.len;
    }
}

fn findTruncationPoint(self: *TextEngine, text: []const u8, size_px: u16, max_width: f32, letter_spacing: f32) usize {
    const ellipsis_w = measureLineWidth(self, "...", size_px, letter_spacing);
    const avail = max_width - ellipsis_w;
    if (avail <= 0) {
        return 0;
    }
    var pen: f32 = 0;
    var last_ok: usize = 0;
    var i: usize = 0;
    var char_count: usize = 0;
    while (i < text.len) {
        const ch = decodeUtf8(text[i..]);
        var adv: f32 = 0;
        if (rasterizeGlyph(self, ch.codepoint, size_px)) |g|         adv = @floatFromInt(g.advance);
        if (char_count > 0) {
            adv += letter_spacing;
        }
        if (pen + adv > avail) {
            break;
        }
        pen += adv;
        i += ch.len;
        char_count += 1;
        last_ok = i;
    }
    return last_ok;
}

pub fn drawTextTruncated(self: *TextEngine, text: []const u8, x: f32, y: f32, size_px: u16, max_width: f32, color: Color, letter_spacing: f32) void {
    const full_w = measureLineWidth(self, text, size_px, letter_spacing);
    if (full_w <= max_width) {
        drawTextEx(self, text, x, y, size_px, color, &letter_spacing);
        return;
    }
    const trunc = findTruncationPoint(self, text, size_px, max_width, letter_spacing);
    if (trunc == 0) {
        drawTextEx(self, "...", x, y, size_px, color, &letter_spacing);
        return;
    }
    drawTextEx(self, text[0..trunc], x, y, size_px, color, &letter_spacing);
    const prefix_w = measureLineWidth(self, text[0..trunc], size_px, letter_spacing);
    drawTextEx(self, "...", x + prefix_w, y, size_px, color, &letter_spacing);
}

pub fn drawTextWrappedFull(self: *TextEngine, text: []const u8, x: f32, y: f32, size_px: u16, max_width: f32, color: Color, text_align: TextAlign, letter_spacing: f32, line_height_override: f32, max_lines: u16) void {
    if (max_width <= 0) {
        drawTextEx(self, text, x, y, size_px, color, &letter_spacing);
        return;
    }
    const lm = lineMetrics(self, size_px);
    const effective_lh = if (line_height_override > 0) line_height_override else lm.height;
    var wrap_width = max_width;
    if (letter_spacing > 0) {
        const avg_adv = cpAdvance(self, "M", size_px);
        if (avg_adv > 0) {
            const ratio = avg_adv / (avg_adv + letter_spacing);
            wrap_width = max_width * ratio;
        }
    }
    const wrap = wordWrap(self, text, size_px, wrap_width);
    var line_count = wrap.count;
    const is_truncated = (max_lines > 0 and line_count > @as(usize, @intCast(max_lines)));
    if (is_truncated) {
        line_count = max_lines;
    }
    {
        var li: usize = 0;
        while (li < line_count) : (li += 1) {
            const line = text[wrap.line_starts[li]..wrap.line_ends[li]];
            const line_y = y + effective_lh * @as(f32, @floatFromInt(li));
            const is_last_truncated = is_truncated and li + 1 == line_count;
            var line_x = x;
            if (text_align != .left and !is_last_truncated) {
                const line_w = measureLineWidth(self, line, size_px, letter_spacing);
                if (text_align == .center) {
                    line_x = x + (max_width - line_w) / 2.0;
                } else {
                    line_x = x + max_width - line_w;
                }
            }
            if (is_last_truncated) {
                drawTextTruncated(self, line, line_x, line_y, size_px, max_width, color, &letter_spacing);
            } else {
                drawTextEx(self, line, line_x, line_y, size_px, color, &letter_spacing);
            }
        }
    }
}

pub fn drawColorSpans(self: *TextEngine, spans: []const ColorSpan, x: f32, y: f32, size_px: u16) void {
    var cx = x;
    for (spans) |*span| {
        drawText(self, span.text, cx, y, size_px, span.color);
        cx += measureLineWidth(self, span.text, size_px, 0);
    }
}

pub fn hitTestWrappedAligned(self: *TextEngine, text: []const u8, local_x: f32, local_y: f32, size_px: u16, max_width: f32, text_align: TextAlign) usize {
    if (text.len == 0) {
        return 0;
    }
    const lm = lineMetrics(self, size_px);
    const wrap = if (max_width > 0) wordWrap(self, text, size_px, max_width) else blk;
    :;
    .{ let, .w = WrapResult, =, .{ .line_starts = null, .line_ends = null, .count = 0 }, ;, wrapAddLine(&w, 0, text.len), ;, .@"break" = blk, w, ; };
    var line_idx: usize = 0;
    if (lm.height > 0) {
        const li = @as(usize, @intFromFloat(@max(0, local_y) / lm.height));
        line_idx = @min(li, if (wrap.count > 0) wrap.count - 1 else 0);
    }
    const line_start = wrap.line_starts[line_idx];
    const line_end = wrap.line_ends[line_idx];
    const line = text[line_start..line_end];
    var align_offset: f32 = 0;
    if (text_align != .left and max_width > 0) {
        var line_w: f32 = 0;
        var lj: usize = 0;
        while (lj < line.len) {
            const lch = decodeUtf8(line[lj..]);
            line_w += cpAdvance(self, lch.codepoint, size_px);
            lj += lch.len;
        }
        if (text_align == .center) {
            align_offset = (max_width - line_w) / 2.0;
        } else {
            align_offset = max_width - line_w;
        }
    }
    const adjusted_x = local_x - align_offset;
    var pen_x: f32 = 0;
    var i: usize = 0;
    var last_byte: usize = 0;
    while (i < line.len) {
        const ch = decodeUtf8(line[i..]);
        const adv = cpAdvance(self, ch.codepoint, size_px);
        if (pen_x + adv / 2.0 > adjusted_x) {
            return line_start + last_byte;
        }
        pen_x += adv;
        last_byte = i;
        i += ch.len;
    }
    return line_end;
}

pub fn drawSelectionRects(self: *TextEngine, text: []const u8, x: f32, y: f32, size_px: u16, max_width: f32, sel_start: usize, sel_end: usize, highlight_color: Color) void {
    if (sel_start == sel_end or text.len == 0) {
        return;
    }
    const s0 = @min(sel_start, sel_end);
    const s1 = @max(sel_start, sel_end);
    const lm = lineMetrics(self, size_px);
    const wrap = if (max_width > 0) wordWrap(self, text, size_px, max_width) else blk;
    :;
    .{ let, .w = WrapResult, =, .{ .line_starts = null, .line_ends = null, .count = 0 }, ;, wrapAddLine(&w, 0, text.len), ;, .@"break" = blk, w, ; };
    _ = c.SDL_SetRenderDrawBlendMode(self.renderer, c.SDL_BLENDMODE_BLEND);
    _ = c.SDL_SetRenderDrawColor(self.renderer, highlight_color.r, highlight_color.g, highlight_color.b, highlight_color.a);
    {
        var li: usize = 0;
        while (li < wrap.count) : (li += 1) {
            const ls = wrap.line_starts[li];
            const le = wrap.line_ends[li];
            if (le <= s0 or ls >= s1) {
                continue;
            }
            const sel_line_start = if (s0 > ls) s0 - ls else 0;
            const sel_line_end = if (s1 < le) s1 - ls else le - ls;
            const line = text[ls..le];
            const line_y = y + lm.height * @as(f32, @floatFromInt(li));
            var x0: f32 = 0;
            var x1: f32 = 0;
            var pen: f32 = 0;
            var bi: usize = 0;
            while (bi < line.len) {
                if (bi == sel_line_start) {
                    x0 = pen;
                }
                const ch = decodeUtf8(line[bi..]);
                pen += cpAdvance(self, ch.codepoint, size_px);
                bi += ch.len;
                if (bi == sel_line_end) {
                    x1 = pen;
                    break;
                }
            }
            if (sel_line_end >= @as(f32, @floatFromInt(line.len))) {
                x1 = pen;
            }
            if (sel_line_start == 0 and x0 == 0 and sel_line_end == 0) {
                continue;
            }
            var rect = c.SDL_Rect{ .x = @intFromFloat(x + x0), .y = @intFromFloat(line_y), .w = @intFromFloat(x1 - x0), .h = @intFromFloat(lm.height) };
            _ = c.SDL_RenderFillRect(self.renderer, &rect);
        }
    }
}

pub fn wordBoundsAt(text: []const u8, byte_idx: usize) struct {
    start;
    :;
    usize;
    ,;
    end;
    :;
    usize;
}
